#!/usr/bin/env python3
"""
FortiGate Config Push Tool

Pushes FortiOS CLI configuration to a FortiGate device via REST API.
Translates CLI config blocks into API calls for automated deployment.

This closes the automation gap - AI can now:
1. Generate config (blueprint-planner)
2. Push config (this tool)
3. Verify deployment (sdwan-status)
4. Track in manifest (manifest-tracker)
"""

import json
import re
import ssl
import urllib.request
import urllib.error
from pathlib import Path
from typing import Any, Dict, List, Optional, Tuple
from datetime import datetime

# Credentials path
CREDS_PATH = Path("C:/ProgramData/Ulysses/config/fortigate_credentials.yaml")


def load_credentials() -> dict:
    """Load FortiGate credentials from config file."""
    import yaml
    if not CREDS_PATH.exists():
        raise FileNotFoundError(f"Credentials file not found: {CREDS_PATH}")
    with open(CREDS_PATH) as f:
        return yaml.safe_load(f)


def get_device_creds(host: str, creds: dict) -> Tuple[str, bool]:
    """Get API token for a device."""
    devices = creds.get("devices", {})

    # Try exact key match first (device name)
    if host in devices:
        dev = devices[host]
        return dev.get("api_token", ""), not dev.get("verify_ssl", True)

    # Try default_lookup table (IP -> device name)
    default_lookup = creds.get("default_lookup", {})
    if host in default_lookup:
        device_name = default_lookup[host]
        if device_name in devices:
            dev = devices[device_name]
            return dev.get("api_token", ""), not dev.get("verify_ssl", True)

    # Try searching by host field in devices
    for name, dev in devices.items():
        if dev.get("host") == host:
            return dev.get("api_token", ""), not dev.get("verify_ssl", True)

    # Try default
    default = creds.get("default", {})
    return default.get("api_token", ""), not default.get("verify_ssl", True)


def make_api_request(host: str, endpoint: str, api_token: str,
                     method: str = "GET", data: dict = None,
                     verify_ssl: bool = True) -> dict:
    """Make FortiGate API request."""
    url = f"https://{host}{endpoint}"

    headers = {
        "Authorization": f"Bearer {api_token}",
        "Content-Type": "application/json",
    }

    body = json.dumps(data).encode() if data else None

    req = urllib.request.Request(url, data=body, headers=headers, method=method)

    ctx = ssl.create_default_context()
    if not verify_ssl:
        ctx.check_hostname = False
        ctx.verify_mode = ssl.CERT_NONE

    try:
        with urllib.request.urlopen(req, context=ctx, timeout=30) as resp:
            return json.loads(resp.read().decode())
    except urllib.error.HTTPError as e:
        error_body = e.read().decode() if e.fp else ""
        return {"http_status": e.code, "error": str(e), "details": error_body}
    except Exception as e:
        return {"error": str(e)}


# CLI to API path mappings
CLI_TO_API_MAP = {
    "system global": "/api/v2/cmdb/system/global",
    "system interface": "/api/v2/cmdb/system/interface",
    "vpn ipsec phase1-interface": "/api/v2/cmdb/vpn.ipsec/phase1-interface",
    "vpn ipsec phase2-interface": "/api/v2/cmdb/vpn.ipsec/phase2-interface",
    "router static": "/api/v2/cmdb/router/static",
    "router bgp": "/api/v2/cmdb/router/bgp",
    "firewall address": "/api/v2/cmdb/firewall/address",
    "firewall policy": "/api/v2/cmdb/firewall/policy",
    "system sdwan": "/api/v2/cmdb/system/sdwan",
}


def parse_cli_config(config_text: str) -> List[dict]:
    """
    Parse FortiOS CLI config into structured blocks.

    Returns list of config blocks with:
    - section: e.g., "system interface"
    - entries: list of {name: str, settings: dict}
    """
    blocks = []
    current_section = None
    current_entry = None
    current_settings = {}
    in_subsection = False
    subsection_name = None
    subsection_entries = []

    lines = config_text.strip().split('\n')

    for line in lines:
        line = line.rstrip()
        stripped = line.strip()

        # Skip comments and empty lines
        if not stripped or stripped.startswith('#'):
            continue

        # Start of config section
        if stripped.startswith('config '):
            section = stripped[7:].strip()

            # Check if this is a subsection (indented config)
            if current_section and line.startswith('    config '):
                in_subsection = True
                subsection_name = section
                subsection_entries = []
            else:
                # Save previous section if exists
                if current_section and current_entry:
                    blocks.append({
                        "section": current_section,
                        "entry": current_entry,
                        "settings": current_settings
                    })
                current_section = section
                current_entry = None
                current_settings = {}

        # Edit command - new entry
        elif stripped.startswith('edit '):
            entry_name = stripped[5:].strip().strip('"\'')

            if in_subsection:
                if subsection_entries:
                    # Save previous subsection entry
                    pass
                subsection_entries.append({"id": entry_name, "settings": {}})
            else:
                # Save previous entry if exists
                if current_entry:
                    blocks.append({
                        "section": current_section,
                        "entry": current_entry,
                        "settings": current_settings
                    })
                current_entry = entry_name
                current_settings = {}

        # Set command
        elif stripped.startswith('set '):
            match = re.match(r'set\s+(\S+)\s+(.*)', stripped)
            if match:
                key = match.group(1)
                value = match.group(2).strip().strip('"')

                # Handle space-separated lists (like "set members 3 4")
                if ' ' in value and not value.startswith('"'):
                    # Could be a list or a single value with spaces
                    parts = value.split()
                    # Check if all parts are numeric (member list)
                    if all(p.isdigit() for p in parts):
                        value = [int(p) for p in parts]
                    elif key in ['srcintf', 'dstintf', 'srcaddr', 'dstaddr', 'service']:
                        # These are typically lists
                        value = [p.strip('"') for p in parts]

                if in_subsection and subsection_entries:
                    subsection_entries[-1]["settings"][key] = value
                else:
                    current_settings[key] = value

        # Next command - finalize entry
        elif stripped == 'next':
            if in_subsection:
                pass  # subsection entry done
            else:
                if current_entry:
                    blocks.append({
                        "section": current_section,
                        "entry": current_entry,
                        "settings": current_settings
                    })
                    current_entry = None
                    current_settings = {}

        # End command
        elif stripped == 'end':
            if in_subsection:
                # Add subsection to current settings
                current_settings[subsection_name] = subsection_entries
                in_subsection = False
                subsection_name = None
                subsection_entries = []
            else:
                # Save final entry or section (handle sections without edit like system global)
                if current_section and (current_entry or current_settings):
                    blocks.append({
                        "section": current_section,
                        "entry": current_entry,  # May be None for system global
                        "settings": current_settings
                    })
                current_section = None
                current_entry = None
                current_settings = {}

    return blocks


def cli_settings_to_api(section: str, entry: str, settings: dict) -> dict:
    """Convert CLI settings to API payload format."""
    payload = {}

    # Map CLI keys to API keys (most are the same, some differ)
    key_map = {
        "psksecret": "psksecret",
        "remote-gw": "remote-gw",
        "ike-version": "ike-version",
        "net-device": "net-device",
        "exchange-ip-addr4": "exchange-ip-addr4",
        "auto-discovery-receiver": "auto-discovery-receiver",
        "auto-discovery-sender": "auto-discovery-sender",
        "network-overlay": "network-overlay",
        "network-id": "network-id",
        "add-route": "add-route",
        "dpd": "dpd",
        "dpd-retrycount": "dpd-retrycount",
        "dpd-retryinterval": "dpd-retryinterval",
        "phase1name": "phase1name",
        "auto-negotiate": "auto-negotiate",
        "embed-measured-health": "embed-measured-health",
        "update-cascade-interface": "update-cascade-interface",
        "update-static-route": "update-static-route",
        "sla-id-redistribute": "sla-id-redistribute",
    }

    for key, value in settings.items():
        api_key = key_map.get(key, key)

        # Convert values
        if isinstance(value, str):
            if value.lower() in ['enable', 'disable']:
                payload[api_key] = value.lower()
            elif value.isdigit():
                payload[api_key] = int(value)
            else:
                payload[api_key] = value
        elif isinstance(value, list):
            # Handle member lists, interface lists, etc.
            if key == "members" and section == "system sdwan":
                # SD-WAN health-check members format
                payload[api_key] = " ".join(str(v) for v in value)
            else:
                payload[api_key] = value
        else:
            payload[api_key] = value

    return payload


def push_config_block(host: str, api_token: str, block: dict,
                      verify_ssl: bool = True) -> dict:
    """Push a single config block to the device."""
    section = block["section"]
    entry = block.get("entry")
    settings = block.get("settings", {})

    # Get API endpoint
    base_endpoint = CLI_TO_API_MAP.get(section)
    if not base_endpoint:
        return {"success": False, "error": f"Unknown section: {section}", "block": block}

    # Special handling for different section types
    if section == "system global":
        # Global settings - PUT without entry name
        endpoint = base_endpoint
        method = "PUT"
        payload = cli_settings_to_api(section, entry, settings)

        result = make_api_request(host, endpoint, api_token, method, payload, verify_ssl)
        return {
            "success": result.get("http_status", 200) in [200, 201] or "error" not in result,
            "section": section,
            "entry": entry,
            "result": result
        }

    elif section == "system sdwan":
        # SD-WAN is complex - handle subsections
        return push_sdwan_config(host, api_token, block, verify_ssl)

    elif section == "router bgp":
        # BGP is also complex
        return push_bgp_config(host, api_token, block, verify_ssl)

    else:
        # Standard entries - try PUT first (update), then POST (create)
        endpoint = f"{base_endpoint}/{entry}"
        payload = cli_settings_to_api(section, entry, settings)

        # Include the name/edit field
        if section == "system interface":
            payload["name"] = entry
        elif section in ["vpn ipsec phase1-interface", "vpn ipsec phase2-interface"]:
            payload["name"] = entry
        elif section == "firewall address":
            payload["name"] = entry
        elif section == "firewall policy":
            payload["policyid"] = int(entry) if entry.isdigit() else entry
        elif section == "router static":
            payload["seq-num"] = int(entry) if entry.isdigit() else entry

        # Try PUT first
        result = make_api_request(host, endpoint, api_token, "PUT", payload, verify_ssl)

        if result.get("http_status") == 404:
            # Entry doesn't exist, try POST to create
            result = make_api_request(host, base_endpoint, api_token, "POST", payload, verify_ssl)

        return {
            "success": result.get("http_status", 200) in [200, 201] or "error" not in result,
            "section": section,
            "entry": entry,
            "result": result
        }


def push_sdwan_config(host: str, api_token: str, block: dict,
                      verify_ssl: bool = True) -> dict:
    """Push SD-WAN configuration (complex nested structure)."""
    settings = block.get("settings", {})
    results = []

    # Enable SD-WAN
    if "status" in settings:
        result = make_api_request(
            host, "/api/v2/cmdb/system/sdwan",
            api_token, "PUT", {"status": settings["status"]}, verify_ssl
        )
        results.append({"action": "enable sdwan", "result": result})

    # Handle zones
    if "zone" in settings:
        for zone in settings["zone"]:
            zone_data = {"name": zone.get("id", zone.get("name"))}
            zone_data.update(zone.get("settings", {}))

            result = make_api_request(
                host, f"/api/v2/cmdb/system/sdwan/zone/{zone_data['name']}",
                api_token, "PUT", zone_data, verify_ssl
            )
            if result.get("http_status") == 404:
                result = make_api_request(
                    host, "/api/v2/cmdb/system/sdwan/zone",
                    api_token, "POST", zone_data, verify_ssl
                )
            results.append({"action": f"zone {zone_data['name']}", "result": result})

    # Handle members
    if "members" in settings:
        for member in settings["members"]:
            member_data = {"seq-num": int(member.get("id", member.get("seq-num", 0)))}
            member_data.update(member.get("settings", {}))

            result = make_api_request(
                host, f"/api/v2/cmdb/system/sdwan/members/{member_data['seq-num']}",
                api_token, "PUT", member_data, verify_ssl
            )
            if result.get("http_status") == 404:
                result = make_api_request(
                    host, "/api/v2/cmdb/system/sdwan/members",
                    api_token, "POST", member_data, verify_ssl
                )
            results.append({"action": f"member {member_data['seq-num']}", "result": result})

    # Handle health-checks
    if "health-check" in settings:
        for hc in settings["health-check"]:
            hc_data = {"name": hc.get("id", hc.get("name"))}
            hc_data.update(hc.get("settings", {}))

            result = make_api_request(
                host, f"/api/v2/cmdb/system/sdwan/health-check/{hc_data['name']}",
                api_token, "PUT", hc_data, verify_ssl
            )
            if result.get("http_status") == 404:
                result = make_api_request(
                    host, "/api/v2/cmdb/system/sdwan/health-check",
                    api_token, "POST", hc_data, verify_ssl
                )
            results.append({"action": f"health-check {hc_data['name']}", "result": result})

    # Handle neighbors
    if "neighbor" in settings:
        for neighbor in settings["neighbor"]:
            neighbor_data = {"ip": neighbor.get("id", neighbor.get("ip"))}
            neighbor_data.update(neighbor.get("settings", {}))

            result = make_api_request(
                host, f"/api/v2/cmdb/system/sdwan/neighbor/{neighbor_data['ip']}",
                api_token, "PUT", neighbor_data, verify_ssl
            )
            if result.get("http_status") == 404:
                result = make_api_request(
                    host, "/api/v2/cmdb/system/sdwan/neighbor",
                    api_token, "POST", neighbor_data, verify_ssl
                )
            results.append({"action": f"neighbor {neighbor_data['ip']}", "result": result})

    success = all(
        r.get("result", {}).get("http_status", 200) in [200, 201] or
        "error" not in r.get("result", {})
        for r in results
    )

    return {"success": success, "section": "system sdwan", "results": results}


def push_bgp_config(host: str, api_token: str, block: dict,
                    verify_ssl: bool = True) -> dict:
    """Push BGP configuration."""
    settings = block.get("settings", {})
    results = []

    # Base BGP settings
    bgp_base = {}
    for key in ["as", "router-id", "ibgp-multipath", "ebgp-multipath",
                "recursive-next-hop", "graceful-restart"]:
        if key in settings:
            bgp_base[key] = settings[key]

    if bgp_base:
        result = make_api_request(
            host, "/api/v2/cmdb/router/bgp",
            api_token, "PUT", bgp_base, verify_ssl
        )
        results.append({"action": "bgp base", "result": result})

    # Handle neighbors
    if "neighbor" in settings:
        for neighbor in settings["neighbor"]:
            neighbor_data = {"ip": neighbor.get("id", neighbor.get("ip"))}
            neighbor_data.update(neighbor.get("settings", {}))

            result = make_api_request(
                host, f"/api/v2/cmdb/router/bgp/neighbor/{neighbor_data['ip']}",
                api_token, "PUT", neighbor_data, verify_ssl
            )
            if result.get("http_status") == 404:
                result = make_api_request(
                    host, "/api/v2/cmdb/router/bgp/neighbor",
                    api_token, "POST", neighbor_data, verify_ssl
                )
            results.append({"action": f"neighbor {neighbor_data['ip']}", "result": result})

    # Handle neighbor-groups
    if "neighbor-group" in settings:
        for ng in settings["neighbor-group"]:
            ng_data = {"name": ng.get("id", ng.get("name"))}
            ng_data.update(ng.get("settings", {}))

            result = make_api_request(
                host, f"/api/v2/cmdb/router/bgp/neighbor-group/{ng_data['name']}",
                api_token, "PUT", ng_data, verify_ssl
            )
            if result.get("http_status") == 404:
                result = make_api_request(
                    host, "/api/v2/cmdb/router/bgp/neighbor-group",
                    api_token, "POST", ng_data, verify_ssl
                )
            results.append({"action": f"neighbor-group {ng_data['name']}", "result": result})

    # Handle neighbor-range
    if "neighbor-range" in settings:
        for nr in settings["neighbor-range"]:
            nr_data = {"id": int(nr.get("id", 1))}
            nr_data.update(nr.get("settings", {}))

            result = make_api_request(
                host, f"/api/v2/cmdb/router/bgp/neighbor-range/{nr_data['id']}",
                api_token, "PUT", nr_data, verify_ssl
            )
            if result.get("http_status") == 404:
                result = make_api_request(
                    host, "/api/v2/cmdb/router/bgp/neighbor-range",
                    api_token, "POST", nr_data, verify_ssl
                )
            results.append({"action": f"neighbor-range {nr_data['id']}", "result": result})

    success = all(
        r.get("result", {}).get("http_status", 200) in [200, 201] or
        "error" not in r.get("result", {})
        for r in results
    )

    return {"success": success, "section": "router bgp", "results": results}


def push_config(host: str, config_text: str = None, config_path: str = None) -> dict:
    """
    Push FortiOS CLI configuration to a device.

    Args:
        host: Target FortiGate IP/hostname
        config_text: CLI config as string
        config_path: Path to CLI config file

    Returns:
        dict with success status and details
    """
    # Load config
    if config_path:
        with open(config_path, 'r') as f:
            config_text = f.read()
    elif not config_text:
        return {"success": False, "error": "No config provided"}

    # Load credentials
    try:
        creds = load_credentials()
        api_token, skip_verify = get_device_creds(host, creds)
        if not api_token:
            return {"success": False, "error": f"No API token for {host}"}
    except Exception as e:
        return {"success": False, "error": f"Credentials error: {e}"}

    # Parse config
    blocks = parse_cli_config(config_text)
    if not blocks:
        return {"success": False, "error": "No config blocks parsed"}

    # Push each block
    results = []
    success_count = 0
    fail_count = 0

    for block in blocks:
        result = push_config_block(host, api_token, block, not skip_verify)
        results.append(result)

        if result.get("success"):
            success_count += 1
        else:
            fail_count += 1

    return {
        "success": fail_count == 0,
        "target": host,
        "blocks_total": len(blocks),
        "blocks_success": success_count,
        "blocks_failed": fail_count,
        "results": results,
        "pushed_at": datetime.now().isoformat()
    }


def main(context) -> dict[str, Any]:
    """
    FortiGate Config Push - Push CLI config to device via API.

    Args:
        context: ExecutionContext with parameters:
            Required:
            - target_ip: FortiGate management IP

            One of:
            - config_path: Path to CLI config file
            - config_text: CLI config as string

            Optional:
            - dry_run: Parse only, don't push (default: false)

    Returns:
        dict: Push results with success/failure details
    """
    if hasattr(context, "parameters"):
        args = context.parameters
    else:
        args = context

    target_ip = args.get("target_ip")
    if not target_ip:
        return {"success": False, "error": "target_ip is required"}

    config_path = args.get("config_path")
    config_text = args.get("config_text")
    dry_run = args.get("dry_run", False)

    if not config_path and not config_text:
        return {"success": False, "error": "config_path or config_text required"}

    # Load config for parsing
    if config_path:
        try:
            with open(config_path, 'r') as f:
                config_text = f.read()
        except Exception as e:
            return {"success": False, "error": f"Failed to read config: {e}"}

    # Parse config
    blocks = parse_cli_config(config_text)

    if dry_run:
        return {
            "success": True,
            "mode": "dry_run",
            "target": target_ip,
            "blocks_parsed": len(blocks),
            "blocks": [{"section": b["section"], "entry": b.get("entry")} for b in blocks]
        }

    # Push config
    return push_config(target_ip, config_text=config_text)


if __name__ == "__main__":
    import sys

    if len(sys.argv) < 3:
        print("Usage: python tool.py <target_ip> <config_file> [--dry-run]")
        sys.exit(1)

    target_ip = sys.argv[1]
    config_file = sys.argv[2]
    dry_run = "--dry-run" in sys.argv

    result = main({
        "target_ip": target_ip,
        "config_path": config_file,
        "dry_run": dry_run
    })

    print(json.dumps(result, indent=2))
